Door -> {
  Transition -> { String:action }
  -> {
    String:state >>- Transition -> "closed"
    Transition -< e {
      state -<< e.action ? {
        "open" -> "opened"
        "close" -> "closed"
        "lock" -> "locked"
        -> state
      }
    }
    open -> { >- Transition{action -> "open"} }
    close -> { >- Transition{action -> "close"} }
    -> state
  }
}
